class Solution:
    def maximumSum(self, arr):
        n = len(arr)
        best = arr[0]
        for i in range(n):
            total = 0
            mn = float('inf')
            for j in range(i, n):
                total += arr[j]
                mn = min(mn, arr[j])
                best = max(best, total)
                if j > i:
                    best = max(best, total - mn)
        return best

