class Solution:
    def maximumSum(self, arr):
        no_del = arr[0]
        one_del = float('-inf')
        best = arr[0]
        for x in arr[1:]:
            one_del = max(no_del, one_del + x)
            no_del = max(no_del + x, x)
            best = max(best, no_del, one_del)
        return best

solutions.javascript:
var maximumSum = function(arr) {
    let noDel = arr[0];
    let oneDel = -Infinity;
    let best = arr[0];
    for (let i = 1; i < arr.length; i++) {
        const x = arr[i];
        oneDel = Math.max(noDel, oneDel + x);
        noDel = Math.max(noDel + x, x);
        best = Math.max(best, noDel, oneDel);
    }
    return best;
};
